def parse_inline_match(match: re.Match[str]) -> dict[str, Any]:
    """Parse regex match into tool arguments."""
    args: dict[str, Any] = {}
    if match.group(1):
        args["pattern"] = match.group(1)
    if match.group(2):
        args["verbose"] = match.group(2) == "true"
    return args
</search>
